#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int n,m,color[N];
vector<int> g[N];
struct node
{
	int u,v,w;
	bool operator<(const node other) const
	{
		return w<other.w;
	}
} a[N];
bool flag;
void dfs(int u,int colorr)
{
	color[u]=colorr;
	for(int i=0;i<g[u].size();i++)
	{
		if(!flag) return ;
		int v=g[u][i];
		if(!color[v]) dfs(v,3-colorr);
		else if(color[v]==colorr) flag=0;
	}
}
bool check(int mid)
{
	for(int i=1;i<=n;i++) g[i].clear();
	for(int i=mid+1;i<=m;i++)
	{
		g[a[i].u].push_back(a[i].v);
		g[a[i].v].push_back(a[i].u);
	}
	flag=1;
	memset(color,0,sizeof(color));
	for(int i=1;i<=n;i++)
	{
		if(!color[i])
		{
			dfs(i,1);
			if(!flag) return 0;
		}
	}
	return 1;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=m;i++)
	{
		cin>>a[i].u>>a[i].v>>a[i].w;
	}
	sort(a+1,a+1+m);
	int l=0,r=m,mid;
	while(l<=r)
	{
		mid=(l+r)/2;
		if(check(mid)) r=mid-1;
		else l=mid+1;
	}
	cout<<a[r+1].w;
	return 0;
}
